import java.util.Arrays;

public class ScratchPad {

    public static int collectMax(int[][] mat) {
        int N = mat.length;
        int[][] dp = new int[N][N];

        // Initialize the dp array with minimum values
        for (int[] row : dp) {
            Arrays.fill(row, Integer.MIN_VALUE);
        }
        dp[0][0] = mat[0][0] == -1 ? 0 : mat[0][0];

        // Iterate through all possible paths
        for (int t = 1; t <= 2 * N - 2; ++t) {
            int[][] dp2 = new int[N][N];
            for (int[] row : dp2) {
                Arrays.fill(row, Integer.MIN_VALUE);
            }

            for (int i = Math.max(0, t - (N - 1)); i <= Math.min(N - 1, t); ++i) {
                for (int j = Math.max(0, t - (N - 1)); j <= Math.min(N - 1, t); ++j) {
                    if (mat[i][t - i] == -1 || mat[j][t - j] == -1) continue;
                    int val = mat[i][t - i];
                    if (i != j) val += mat[j][t - j];

                    for (int pi = i - 1; pi <= i; ++pi)
                        for (int pj = j - 1; pj <= j; ++pj)
                            if (pi >= 0 && pj >= 0)
                                dp2[i][j] = Math.max(dp2[i][j], dp[pi][pj] + val);
                }
            }
            dp = dp2;
        }
        return Math.max(0, dp[N - 1][N - 1]);
    }

    public static void main(String[] args) {
        // Test cases
        int[][] case0 = { {0, 1, -1}, {1, 0, -1}, {1, 1, 1} };
        int[][] case1 = { {0, 1, 1}, {1, 0, 1}, {1, 1, 1} };
        int[][] case2 = { {0, 1, 1}, {1, 0, -1}, {1, 1, -1} };

        System.out.println("Case 0 Output: " + collectMax(case0)); // Expected: 5
        System.out.println("Case 1 Output: " + collectMax(case1)); // Expected: 7
        System.out.println("Case 2 Output: " + collectMax(case2)); // Expected: 0
    }
}
